import { useEffect, useMemo, useState } from 'react'
import { createAdminAccount, deleteAdminAccount, getAdminAccount, updateAdminAccountById } from '@/api/admin'
import type { AdminAccount, AdminUser } from '@/api/types'
import { useAuth } from '@/store/auth'

const inputCls =
  'h-10 w-full rounded-lg border border-zinc-200 bg-white px-3 text-sm text-zinc-900 outline-none focus:border-zinc-900'

function Field({ label, children }: { label: string; children: React.ReactNode }) {
  return (
    <label className="grid gap-1">
      <span className="text-xs text-zinc-600">{label}</span>
      {children}
    </label>
  )
}

function accountMessage(message: string) {
  const map: Record<string, string> = {
    mysql_not_configured: 'MySQL 未配置，暂时只能使用云托管环境变量账号登录。',
    admin_email_invalid: '请输入正确的邮箱。',
    admin_password_too_short: '密码至少 6 位。',
    current_password_invalid: '当前登录密码不正确。',
    admin_email_exists: '这个邮箱已经存在。',
    admin_user_not_found: '管理员账号不存在。',
    last_admin_user: '至少需要保留一个数据库管理员账号。',
    last_super_admin: '至少需要保留一个超级管理员。',
    permission_denied: '当前账号没有权限管理其他管理员。'
  }
  return map[message] || message || '操作失败'
}

export default function AdminAccounts() {
  const token = useAuth((s) => s.token)
  const authEmail = useAuth((s) => s.email)
  const setAuth = useAuth((s) => s.setAuth)
  const [account, setAccount] = useState<AdminAccount | null>(null)
  const [loading, setLoading] = useState(false)
  const [saving, setSaving] = useState(false)
  const [error, setError] = useState('')
  const [success, setSuccess] = useState('')
  const [adminEmail, setAdminEmail] = useState('')
  const [adminRole, setAdminRole] = useState<'super_admin' | 'admin'>('admin')
  const [editingAdminId, setEditingAdminId] = useState('')
  const [currentPassword, setCurrentPassword] = useState('')
  const [newPassword, setNewPassword] = useState('')

  async function refresh() {
    if (!token) return
    setError('')
    setLoading(true)
    try {
      setAccount(await getAdminAccount(token))
    } catch (e) {
      setError(e instanceof Error ? e.message : '加载失败')
    } finally {
      setLoading(false)
    }
  }

  useEffect(() => {
    refresh()
  }, [token])

  const canSave = useMemo(
    () => Boolean(token && adminEmail.trim() && currentPassword && (editingAdminId || newPassword)),
    [adminEmail, currentPassword, editingAdminId, newPassword, token]
  )
  const accountUsers = account?.users || []
  const canManageAdmins = Boolean(account?.canManageAdmins)

  function resetForm() {
    setEditingAdminId('')
    setAdminEmail('')
    setAdminRole('admin')
    setCurrentPassword('')
    setNewPassword('')
  }

  function editAccount(user: AdminUser) {
    setEditingAdminId(user.id)
    setAdminEmail(user.email)
    setAdminRole(user.role)
    setCurrentPassword('')
    setNewPassword('')
    setError('')
    setSuccess('')
  }

  async function saveAccount() {
    if (!token || !canSave) return
    setSaving(true)
    setError('')
    setSuccess('')
    try {
      const payload = {
        email: adminEmail.trim(),
        currentPassword,
        newPassword,
        role: adminRole
      }
      const next = editingAdminId
        ? await updateAdminAccountById(token, editingAdminId, payload)
        : await createAdminAccount(token, payload)
      setAccount(next)
      if (!account?.hasDatabaseAccount || authEmail === accountUsers.find((u) => u.id === editingAdminId)?.email) {
        const nextSelf = next.users.find((u) => u.email === adminEmail.trim())
        setAuth(token, adminEmail.trim(), nextSelf?.role || adminRole)
      }
      const wasEditing = Boolean(editingAdminId)
      resetForm()
      setSuccess(wasEditing ? '管理员账号已更新。' : '管理员账号已新增，后续登录可使用该账号。')
    } catch (e) {
      setError(e instanceof Error ? accountMessage(e.message) : '保存失败')
    } finally {
      setSaving(false)
    }
  }

  async function removeAccount(user: AdminUser) {
    if (!token) return
    const password = window.prompt(`请输入当前登录密码，确认删除 ${user.email}`)
    if (!password) return
    setSaving(true)
    setError('')
    setSuccess('')
    try {
      const next = await deleteAdminAccount(token, user.id, { currentPassword: password })
      setAccount(next)
      if (authEmail === user.email && next.users[0]) setAuth(token, next.users[0].email, next.users[0].role)
      if (editingAdminId === user.id) resetForm()
      setSuccess('管理员账号已删除。')
    } catch (e) {
      setError(e instanceof Error ? accountMessage(e.message) : '删除失败')
    } finally {
      setSaving(false)
    }
  }

  return (
    <div>
      <div className="flex items-end justify-between gap-3">
        <div>
          <div className="text-lg font-semibold text-zinc-900">管理员账号</div>
          <div className="mt-1 text-sm text-zinc-500">维护后台登录账号、角色与密码</div>
        </div>
        <button
          type="button"
          disabled={!canSave || saving || (!editingAdminId && account?.hasDatabaseAccount && !canManageAdmins)}
          className="inline-flex h-10 items-center justify-center rounded-lg bg-zinc-900 px-4 text-sm text-white hover:bg-zinc-800 disabled:opacity-60"
          onClick={saveAccount}
        >
          {saving ? '保存中...' : editingAdminId ? '更新账号' : '新增账号'}
        </button>
      </div>

      {error ? <div className="mt-4 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</div> : null}
      {success ? <div className="mt-4 rounded-xl border border-zinc-200 bg-zinc-50 px-4 py-3 text-sm text-zinc-700">{success}</div> : null}

      <div className="mt-5 rounded-2xl border border-zinc-200 bg-white p-5">
        <div className="flex items-start justify-between gap-4">
          <div>
            <div className="text-sm font-semibold text-zinc-900">账号列表</div>
            <div className="mt-1 text-xs text-zinc-500">
              当前来源：{account?.source === 'database' ? '数据库' : '云托管环境变量'} · 当前角色：
              {account?.role === 'super_admin' ? '超级管理员' : '管理员'}
            </div>
          </div>
          <button
            type="button"
            disabled={loading}
            className="inline-flex h-9 items-center rounded-lg border border-zinc-200 px-3 text-xs text-zinc-700 hover:bg-zinc-50 disabled:opacity-60"
            onClick={refresh}
          >
            刷新
          </button>
        </div>

        <div className="mt-4 overflow-hidden rounded-xl border border-zinc-200">
          <div className="grid grid-cols-[1fr_auto] gap-3 bg-zinc-50 px-4 py-3 text-xs font-medium text-zinc-500">
            <div>登录邮箱</div>
            <div>操作</div>
          </div>
          {accountUsers.length ? (
            accountUsers.map((user) => (
              <div key={user.id} className="grid grid-cols-[1fr_auto] items-center gap-3 border-t border-zinc-100 px-4 py-3">
                <div className="min-w-0">
                  <div className="truncate text-sm text-zinc-900">{user.email}</div>
                  <div className="mt-1 text-xs text-zinc-400">
                    {user.role === 'super_admin' ? '超级管理员' : '管理员'}
                    {user.createdAt ? ` · 创建时间：${user.createdAt}` : ''}
                  </div>
                </div>
                <div className="flex items-center gap-2">
                  <button
                    type="button"
                    className="inline-flex h-8 items-center rounded-lg border border-zinc-200 px-3 text-xs text-zinc-700 hover:bg-zinc-50"
                    onClick={() => editAccount(user)}
                  >
                    编辑
                  </button>
                  <button
                    type="button"
                    disabled={saving || accountUsers.length <= 1 || !canManageAdmins}
                    className="inline-flex h-8 items-center rounded-lg border border-red-200 px-3 text-xs text-red-600 hover:bg-red-50 disabled:opacity-40"
                    onClick={() => removeAccount(user)}
                  >
                    删除
                  </button>
                </div>
              </div>
            ))
          ) : (
            <div className="border-t border-zinc-100 px-4 py-4 text-sm text-zinc-500">
              还没有数据库管理员账号，当前可用云托管环境变量账号登录。
            </div>
          )}
        </div>
      </div>

      <div className="mt-4 rounded-2xl border border-zinc-200 bg-white p-5">
        <div className="text-sm font-semibold text-zinc-900">{editingAdminId ? '编辑账号' : '新增账号'}</div>
        <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
          <Field label="登录邮箱">
            <input className={inputCls} value={adminEmail} onChange={(e) => setAdminEmail(e.target.value)} type="email" autoComplete="username" />
          </Field>
          <Field label="当前密码">
            <input className={inputCls} value={currentPassword} onChange={(e) => setCurrentPassword(e.target.value)} type="password" autoComplete="current-password" />
          </Field>
          <Field label={editingAdminId ? '新密码（留空则不修改）' : '新密码'}>
            <input className={inputCls} value={newPassword} onChange={(e) => setNewPassword(e.target.value)} type="password" autoComplete="new-password" />
          </Field>
          {canManageAdmins ? (
            <Field label="账号角色">
              <select className={inputCls} value={adminRole} onChange={(e) => setAdminRole(e.target.value as 'super_admin' | 'admin')}>
                <option value="admin">管理员</option>
                <option value="super_admin">超级管理员</option>
              </select>
            </Field>
          ) : null}
          <div className="flex items-end justify-between gap-3 text-xs text-zinc-500 md:col-span-2">
            <span>{canManageAdmins ? '超级管理员可以新增和管理其他管理员。' : '普通管理员只能查看和修改自己的账号。'}</span>
            {editingAdminId ? (
              <button type="button" className="shrink-0 text-zinc-900 hover:underline" onClick={resetForm}>
                取消编辑
              </button>
            ) : null}
          </div>
        </div>
      </div>
    </div>
  )
}
