import { useCallback, useEffect, useState } from 'react'
import { useAuth } from '@/store/auth'
import type { Lead, LeadNotifyConfig } from '@/api/types'
import { getLeadNotifyConfig, listLeads, testLeadNotify, updateLeadNotifyConfig, updateLeadStatus } from '@/api/admin'
import { Bell, CheckCircle2, RotateCcw, Search, Send } from 'lucide-react'
import Modal from '@/components/Modal'

const inputCls =
  'h-10 w-full rounded-lg border border-zinc-200 bg-white px-3 text-sm text-zinc-900 outline-none focus:border-zinc-900 disabled:bg-zinc-50 disabled:text-zinc-400'

function normalizeMobiles(text: string) {
  return String(text || '')
    .split(/[\s,，;；]+/)
    .map((s) => s.trim())
    .filter(Boolean)
}

export default function Leads() {
  const token = useAuth((s) => s.token)
  const [q, setQ] = useState('')
  const [status, setStatus] = useState('')
  const [items, setItems] = useState<Lead[]>([])
  const [total, setTotal] = useState(0)
  const [loading, setLoading] = useState(false)
  const [error, setError] = useState('')
  const [open, setOpen] = useState(false)
  const [selected, setSelected] = useState<Lead | null>(null)
  const [notifyConfig, setNotifyConfig] = useState<LeadNotifyConfig>({
    enabled: false,
    webhookUrl: '',
    mentionAll: false,
    mentionedMobileList: []
  })
  const [mobilesText, setMobilesText] = useState('')
  const [notifyLoading, setNotifyLoading] = useState(false)
  const [notifySaving, setNotifySaving] = useState(false)
  const [notifyTesting, setNotifyTesting] = useState(false)
  const [notifyMessage, setNotifyMessage] = useState('')
  const [notifyError, setNotifyError] = useState('')
  const [statusSavingId, setStatusSavingId] = useState('')

  const reload = useCallback(async () => {
    if (!token) return
    setError('')
    setLoading(true)
    try {
      const r = await listLeads(token, q, 50, 0, status)
      setItems(r.items)
      setTotal(r.total)
    } catch (e) {
      setError(e instanceof Error ? e.message : '加载失败')
    } finally {
      setLoading(false)
    }
  }, [q, status, token])

  async function markLead(item: Lead, nextStatus: 'pending' | 'contacted') {
    if (!token) return
    setStatusSavingId(item.id)
    setError('')
    try {
      const next = await updateLeadStatus(token, item.id, nextStatus)
      setItems((arr) => {
        const updated = arr.map((it) => (it.id === item.id ? next : it))
        if (status && next.status !== status) return updated.filter((it) => it.id !== item.id)
        return updated
      })
      setSelected((s) => (s && s.id === item.id ? next : s))
      setTotal((t) => (status && next.status !== status ? Math.max(t - 1, 0) : t))
    } catch (e) {
      setError(e instanceof Error ? e.message : '状态更新失败')
    } finally {
      setStatusSavingId('')
    }
  }

  function statusLabel(item: Lead) {
    return item.status === 'contacted' ? '已联系' : '未联系'
  }

  const loadNotifyConfig = useCallback(async () => {
    if (!token) return
    setNotifyLoading(true)
    setNotifyError('')
    try {
      const r = await getLeadNotifyConfig(token)
      setNotifyConfig(r)
      setMobilesText((r.mentionedMobileList || []).join(','))
    } catch (e) {
      setNotifyError(e instanceof Error ? e.message : '通知配置加载失败')
    } finally {
      setNotifyLoading(false)
    }
  }, [token])

  useEffect(() => {
    reload()
  }, [reload])

  useEffect(() => {
    loadNotifyConfig()
  }, [loadNotifyConfig])

  async function saveNotifyConfig() {
    if (!token) return
    setNotifySaving(true)
    setNotifyError('')
    setNotifyMessage('')
    try {
      const payload: LeadNotifyConfig = {
        enabled: notifyConfig.enabled,
        webhookUrl: notifyConfig.webhookUrl,
        mentionAll: notifyConfig.mentionAll,
        mentionedMobileList: normalizeMobiles(mobilesText)
      }
      const r = await updateLeadNotifyConfig(token, payload)
      setNotifyConfig(r)
      setMobilesText((r.mentionedMobileList || []).join(','))
      setNotifyMessage('通知配置已保存')
    } catch (e) {
      setNotifyError(e instanceof Error ? e.message : '通知配置保存失败')
    } finally {
      setNotifySaving(false)
    }
  }

  async function sendNotifyTest() {
    if (!token) return
    setNotifyTesting(true)
    setNotifyError('')
    setNotifyMessage('')
    try {
      await testLeadNotify(token)
      setNotifyMessage('测试消息已发送')
    } catch (e) {
      setNotifyError(e instanceof Error ? e.message : '测试发送失败')
    } finally {
      setNotifyTesting(false)
    }
  }

  return (
    <div>
      <div className="flex items-start justify-between gap-4">
        <div>
          <div className="text-lg font-semibold text-zinc-900">预约管理</div>
          <div className="mt-1 text-sm text-zinc-500">共 {total} 条</div>
        </div>
      </div>

      <div className="mt-4 rounded-2xl border border-zinc-200 bg-white p-5">
        <div className="flex flex-wrap items-start justify-between gap-3">
          <div className="flex items-center gap-3">
            <div className="flex h-9 w-9 items-center justify-center rounded-lg bg-zinc-900 text-white">
              <Bell className="h-4 w-4" />
            </div>
            <div>
              <div className="text-sm font-semibold text-zinc-900">企业微信机器人通知</div>
              <div className="mt-1 text-xs text-zinc-500">开启后，新预约会第一时间推送到群机器人；未配置或发送失败不影响预约提交。</div>
            </div>
          </div>
          <label className="inline-flex items-center gap-2 text-sm text-zinc-700">
            <input
              type="checkbox"
              checked={notifyConfig.enabled}
              disabled={notifyLoading}
              onChange={(e) => setNotifyConfig((s) => ({ ...s, enabled: e.target.checked }))}
            />
            启用通知
          </label>
        </div>

        <div className="mt-4 grid grid-cols-1 gap-4 md:grid-cols-2">
          <label className="grid gap-1 md:col-span-2">
            <span className="text-xs text-zinc-600">机器人 Webhook</span>
            <input
              className={inputCls}
              value={notifyConfig.webhookUrl}
              placeholder={notifyConfig.webhookUrlMasked || 'https://qyapi.weixin.qq.com/cgi-bin/webhook/send?key=...'}
              disabled={notifyLoading}
              onChange={(e) => setNotifyConfig((s) => ({ ...s, webhookUrl: e.target.value }))}
            />
          </label>
          <label className="grid gap-1">
            <span className="text-xs text-zinc-600">@手机号（逗号或空格分隔）</span>
            <input
              className={inputCls}
              value={mobilesText}
              disabled={notifyLoading || notifyConfig.mentionAll}
              placeholder="13800000000, 13900000000"
              onChange={(e) => setMobilesText(e.target.value)}
            />
          </label>
          <label className="mt-6 inline-flex items-center gap-2 text-sm text-zinc-700">
            <input
              type="checkbox"
              checked={notifyConfig.mentionAll}
              disabled={notifyLoading}
              onChange={(e) => setNotifyConfig((s) => ({ ...s, mentionAll: e.target.checked }))}
            />
            通知时 @所有人
          </label>
        </div>

        {notifyError ? <div className="mt-3 rounded-lg border border-red-200 bg-red-50 px-3 py-2 text-sm text-red-700">{notifyError}</div> : null}
        {notifyMessage ? <div className="mt-3 rounded-lg border border-zinc-200 bg-zinc-50 px-3 py-2 text-sm text-zinc-700">{notifyMessage}</div> : null}

        <div className="mt-4 flex justify-end gap-2">
          <button
            type="button"
            disabled={notifyTesting || notifySaving || notifyLoading}
            className="inline-flex h-10 items-center gap-2 rounded-lg border border-zinc-200 px-4 text-sm text-zinc-700 hover:bg-zinc-50 disabled:opacity-60"
            onClick={sendNotifyTest}
          >
            <Send className="h-4 w-4" />
            测试发送
          </button>
          <button
            type="button"
            disabled={notifySaving || notifyLoading}
            className="h-10 rounded-lg bg-zinc-900 px-4 text-sm text-white hover:bg-zinc-800 disabled:opacity-60"
            onClick={saveNotifyConfig}
          >
            保存配置
          </button>
        </div>
      </div>

      <div className="mt-4 flex items-center gap-2 rounded-xl border border-zinc-200 bg-white px-3 py-2">
        <Search className="h-4 w-4 text-zinc-400" />
        <input
          className="w-full bg-transparent text-sm outline-none"
          placeholder="搜索姓名 / 电话 / 小区..."
          value={q}
          onChange={(e) => setQ(e.target.value)}
          onKeyDown={(e) => {
            if (e.key === 'Enter') reload()
          }}
        />
        <button
          type="button"
          className="rounded-lg bg-zinc-900 px-3 py-1.5 text-sm text-white hover:bg-zinc-800"
          onClick={reload}
        >
          查询
        </button>
      </div>

      <div className="mt-3 flex flex-wrap items-center gap-2">
        {[
          { value: '', label: '全部' },
          { value: 'pending', label: '未联系' },
          { value: 'contacted', label: '已联系' }
        ].map((tab) => (
          <button
            key={tab.value || 'all'}
            type="button"
            className={`h-9 rounded-lg px-4 text-sm ${
              status === tab.value ? 'bg-zinc-900 text-white' : 'border border-zinc-200 bg-white text-zinc-700 hover:bg-zinc-50'
            }`}
            onClick={() => setStatus(tab.value)}
          >
            {tab.label}
          </button>
        ))}
      </div>

      {error ? <div className="mt-4 rounded-xl border border-red-200 bg-red-50 px-4 py-3 text-sm text-red-700">{error}</div> : null}

      <div className="mt-4 overflow-hidden rounded-2xl border border-zinc-200 bg-white">
        <div className="grid grid-cols-12 gap-2 border-b border-zinc-200 px-4 py-3 text-xs font-medium text-zinc-500">
          <div className="col-span-3">客户</div>
          <div className="col-span-2">电话</div>
          <div className="col-span-2">小区</div>
          <div className="col-span-1">状态</div>
          <div className="col-span-2">提交时间</div>
          <div className="col-span-2 text-right">操作</div>
        </div>
        {loading ? (
          <div className="px-4 py-6 text-sm text-zinc-500">加载中...</div>
        ) : items.length ? (
          <div>
            {items.map((it) => (
              <div key={it.id} className="grid w-full grid-cols-12 items-center gap-2 px-4 py-3 text-left text-sm hover:bg-zinc-50">
                <div className="col-span-3 flex items-center gap-3">
                  <div className="flex h-8 w-8 items-center justify-center rounded-full border border-zinc-200 bg-zinc-50 text-xs font-semibold text-zinc-700">
                    {(it.nickName || '访').slice(0, 1)}
                  </div>
                  <div className="min-w-0">
                    <div className="truncate font-medium text-zinc-900">{it.nickName}</div>
                    <div className="truncate text-xs text-zinc-500">{it.id}</div>
                  </div>
                </div>
                <div className="col-span-2 truncate font-medium text-zinc-900">{it.phone || '-'}</div>
                <div className="col-span-2 truncate text-zinc-700">{String((it.meta as any)?.community || '-')}</div>
                <div className="col-span-1">
                  <span
                    className={`inline-flex rounded-full px-2 py-1 text-xs ${
                      it.status === 'contacted' ? 'bg-emerald-50 text-emerald-700' : 'bg-amber-50 text-amber-700'
                    }`}
                  >
                    {statusLabel(it)}
                  </span>
                </div>
                <button
                  type="button"
                  className="col-span-2 text-left text-xs text-zinc-500 hover:text-zinc-900"
                  onClick={() => {
                    setSelected(it)
                    setOpen(true)
                  }}
                >
                  {new Date(it.createdAt).toLocaleString()}
                </button>
                <div className="col-span-2 flex justify-end gap-2">
                  <button
                    type="button"
                    disabled={statusSavingId === it.id}
                    className="inline-flex h-8 items-center gap-1 rounded-lg border border-zinc-200 px-2 text-xs text-zinc-700 hover:bg-zinc-50 disabled:opacity-60"
                    onClick={() => markLead(it, it.status === 'contacted' ? 'pending' : 'contacted')}
                  >
                    {it.status === 'contacted' ? <RotateCcw className="h-3.5 w-3.5" /> : <CheckCircle2 className="h-3.5 w-3.5" />}
                    {it.status === 'contacted' ? '恢复' : '已联系'}
                  </button>
                </div>
              </div>
            ))}
          </div>
        ) : (
          <div className="px-4 py-6 text-sm text-zinc-500">暂无数据</div>
        )}
      </div>

      <Modal
        open={open}
        title="预约详情"
        onClose={() => {
          setOpen(false)
          setSelected(null)
        }}
        width="max-w-xl"
      >
        {selected ? (
          <div className="space-y-3 text-sm">
            <div className="flex items-center gap-3">
              <div className="flex h-10 w-10 items-center justify-center rounded-full border border-zinc-200 bg-zinc-50 text-sm font-semibold text-zinc-700">
                {(selected.nickName || '访').slice(0, 1)}
              </div>
              <div>
                <div className="font-medium text-zinc-900">{selected.nickName}</div>
                <div className="text-xs text-zinc-500">{selected.id}</div>
              </div>
            </div>
            <div className="grid grid-cols-3 gap-2">
              <div className="text-xs text-zinc-500">电话</div>
              <div className="col-span-2 font-medium text-zinc-900">{selected.phone || '-'}</div>
              <div className="text-xs text-zinc-500">小区</div>
              <div className="col-span-2 text-zinc-900">{String((selected.meta as any)?.community || '-')}</div>
              <div className="text-xs text-zinc-500">面积</div>
              <div className="col-span-2 text-zinc-900">{String((selected.meta as any)?.area || '-')}</div>
              <div className="text-xs text-zinc-500">需求</div>
              <div className="col-span-2 text-zinc-900">{String((selected.meta as any)?.demand || '-')}</div>
              <div className="text-xs text-zinc-500">状态</div>
              <div className="col-span-2 text-zinc-900">
                {statusLabel(selected)}
                {selected.contactedAt ? ` · ${new Date(selected.contactedAt).toLocaleString()}` : ''}
              </div>
              <div className="text-xs text-zinc-500">提交时间</div>
              <div className="col-span-2 text-zinc-900">{new Date(selected.createdAt).toLocaleString()}</div>
            </div>
            <div className="flex justify-end">
              <button
                type="button"
                disabled={statusSavingId === selected.id}
                className="inline-flex h-10 items-center gap-2 rounded-lg bg-zinc-900 px-4 text-sm text-white hover:bg-zinc-800 disabled:opacity-60"
                onClick={() => markLead(selected, selected.status === 'contacted' ? 'pending' : 'contacted')}
              >
                {selected.status === 'contacted' ? <RotateCcw className="h-4 w-4" /> : <CheckCircle2 className="h-4 w-4" />}
                {selected.status === 'contacted' ? '恢复未联系' : '标记已联系'}
              </button>
            </div>
          </div>
        ) : null}
      </Modal>
    </div>
  )
}
