import type { ContentType } from '@/api/types'

export function contentLabel(type: ContentType) {
  if (type === 'homeBanners') return '首页轮播'
  if (type === 'homeNavs') return '首页导航'
  if (type === 'homeServices') return '品质定制'
  if (type === 'homeAdvantages') return '品牌优势'
  if (type === 'cases') return '案例'
  if (type === 'designers') return '设计师'
  if (type === 'aboutInfos') return '关于-优势块'
  return '关于-历程'
}

export function splitLines(v: string) {
  return String(v || '')
    .split(/\r?\n/)
    .map((s) => s.trim())
    .filter(Boolean)
}

export function joinLines(v: string[]) {
  return (v || []).join('\n')
}
