import { create } from 'zustand'
import { persist } from 'zustand/middleware'

type AuthState = {
  token: string | null
  email: string | null
  role: 'super_admin' | 'admin' | null
  setAuth: (token: string, email: string, role?: 'super_admin' | 'admin') => void
  clear: () => void
}

export const useAuth = create<AuthState>()(
  persist(
    (set) => ({
      token: null,
      email: null,
      role: null,
      setAuth: (token, email, role = 'admin') => set({ token, email, role }),
      clear: () => set({ token: null, email: null, role: null })
    }),
    { name: 'admin_auth_v1' }
  )
)
