export async function uploadImage(token: string, file: File) {
  const form = new FormData()
  form.append('file', file)
  const res = await fetch('/api/admin/upload', {
    method: 'POST',
    headers: { authorization: `Bearer ${token}` },
    body: form
  })
  const text = await res.text()
  let data: any = null
  try {
    data = text ? JSON.parse(text) : null
  } catch (_e) {}
  if (!res.ok) throw new Error((data && data.message) || `HTTP ${res.status}`)
  if (!data || !data.ok) throw new Error((data && data.message) || '上传失败')
  return data.data as UploadResult
}

export async function getFileUrl(token: string, fileId: string) {
  const u = new URL('/api/admin/file-url', window.location.origin)
  u.searchParams.set('fileId', fileId)
  const res = await fetch(u.toString(), { headers: { authorization: `Bearer ${token}` } })
  const text = await res.text()
  let data: any = null
  try {
    data = text ? JSON.parse(text) : null
  } catch (_e) {}
  if (!res.ok) throw new Error((data && data.message) || `HTTP ${res.status}`)
  if (!data || !data.ok) throw new Error((data && data.message) || '获取失败')
  return (data.data && data.data.url) as string
}
