import { useEffect, useMemo, useState } from 'react'
import { getFileUrl } from '@/api/admin'

const cache = new Map<string, { url: string; expireAt: number }>()

function getCached(fileId: string) {
  const v = cache.get(fileId)
  if (!v) return ''
  if (Date.now() > v.expireAt) {
    cache.delete(fileId)
    return ''
  }
  return v.url
}

function setCached(fileId: string, url: string) {
  cache.set(fileId, { url, expireAt: Date.now() + 5 * 60 * 1000 })
}

export default function CloudImage({
  token,
  src,
  className
}: {
  token: string
  src: string
  className?: string
}) {
  const isCloud = useMemo(() => src.startsWith('cloud://'), [src])
  const [url, setUrl] = useState(() => (isCloud ? getCached(src) : src))

  useEffect(() => {
    let mounted = true
    if (!src) {
      setUrl('')
      return
    }
    if (!isCloud) {
      setUrl(src)
      return
    }
    const cached = getCached(src)
    if (cached) {
      setUrl(cached)
      return
    }
    if (!token) {
      setUrl('')
      return
    }
    getFileUrl(token, src)
      .then((u) => {
        if (!mounted) return
        if (u) setCached(src, u)
        setUrl(u || '')
      })
      .catch(() => {
        if (!mounted) return
        setUrl('')
      })
    return () => {
      mounted = false
    }
  }, [src, isCloud, token])

  if (!url) return null
  return <img className={className} src={url} alt="" />
}

